module.exports = async function({ input }) {
  const source = (input && input.body && typeof input.body === 'object') ? input.body : (input || {});
  const raw = (name) => source[name] ?? source[name.toLowerCase()] ?? source[name.toUpperCase()] ?? '';
  const clean = (v) => String(v == null ? '' : v).trim();
  const sql = (v) => clean(v).replace(/'/g, "''");
  const leadId = clean(raw('lead_id') || raw('id') || raw('research_id') || raw('lead_research_id'));
  if (!leadId) throw new Error('Business outreach requires a lead_id.');
  return { lead_id: leadId, lead_id_sql: sql(leadId) };
};

module.exports = async function({ input }) {
  const row = (input && Array.isArray(input.rows) && input.rows[0]) ? input.rows[0] : {};
  const clean = (v) => String(v == null ? '' : v).trim();
  const parseList = (raw) => { try { const v = JSON.parse(raw || '[]'); return Array.isArray(v) ? v : []; } catch (e) { return []; } };
  if (!clean(row.lead_id)) throw new Error('No lead found for outreach. Please provide a valid lead_id.');
  return {
    research_id: clean(row.research_id),
    lead_id: clean(row.lead_id),
    company_name: clean(row.company_name) || 'Unknown',
    website_url: clean(row.website_url) || 'N/A',
    city: clean(row.city) || 'unknown',
    business_type: clean(row.business_type) || 'local business',
    services: clean(row.services) || 'unknown',
    target_customers: clean(row.target_customers) || 'unknown',
    website_quality: clean(row.website_quality) || 'unknown',
    missing_systems: parseList(row.missing_systems).join(', ') || 'unknown',
    pain_points: clean(row.pain_points) || 'unknown',
    recommended_offer: clean(row.recommended_offer) || 'modern website and automation support',
    outreach_angle: clean(row.outreach_angle) || 'specific digital improvement opportunity',
    confidence_score: Number.parseInt(row.confidence_score, 10) || 0,
    source_urls: parseList(row.source_urls).join(', '),
    recipient_email: clean(row.recipient_email).replace(/^N\/A$/i, ''),
    phone: clean(row.phone),
    lead_notes: clean(row.lead_notes)
  };
};

