parameters.script:
module.exports = async function({ input }) {
  let raw = input && (input.output || input.text || input.result || input.content);
  if (raw && typeof raw === 'object' && !Array.isArray(raw)) raw = JSON.stringify(raw);
  raw = String(raw || '{}').replace(/```json/gi, '').replace(/```/g, '').trim();
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start >= 0 && end > start) raw = raw.slice(start, end + 1);
  let parsed = {};
  try { parsed = JSON.parse(raw); } catch (e) { parsed = {}; }
  const esc = (v) => String(v == null ? '' : v).trim().replace(/'/g, "''");
  const clamp = (v) => Math.max(0, Math.min(100, Number.parseInt(v, 10) || 0));
  const signature = 'Viele Grüße\nMohamed Sesay\nFounder & Automation Consultant\nDee Empire\nForststraße 6, 96264 Altenkunstadt\nmsesay@dee-empire.com\nWhatsApp: +49 152 15461719\ndee-empire.com';
  const subject = parsed.subject || 'Kurze Idee für Ihre Online-Präsenz';
  let body = parsed.body || 'Hallo, ich habe mir Ihre Online-Präsenz angesehen und glaube, dass Dee Empire Ihnen mit einer moderneren Website und klarerem Kontakt- oder Buchungsfluss helfen kann. Wenn es passt, sende ich Ihnen gern eine kurze konkrete Idee dazu.';
  body = String(body || '').trim();
  if (!/Mohamed\s+Sesay/i.test(body)) body = body + '\n\n' + signature;
  return {
    recipient_email: esc(parsed.recipient_email || ''),
    subject: esc(subject),
    preview_text: esc(parsed.preview_text || subject),
    body: esc(body),
    pain_point: esc(parsed.pain_point || 'digital presence improvement'),
    offer: esc(parsed.offer || 'modern website and automation support'),
    call_to_action: esc(parsed.call_to_action || 'permission to send a short idea'),
    tone: esc(parsed.tone || 'professional_warm'),
    followup_days: Math.max(1, Math.min(30, Number.parseInt(parsed.followup_days, 10) || 3)),
    confidence_score: clamp(parsed.confidence_score || 50),
    draft_json: esc(JSON.stringify(parsed && typeof parsed === 'object' ? parsed : {}))
  };
};

